const body = $input.first().json.body || $input.first().json;
const envActive = ($env.HOME_AI_OBSERVABILITY_PROFILE_ACTIVE || '').toLowerCase() === 'true';
const bodyActive = body.observability_active === true || String(body.observability_active || '').toLowerCase() === 'true';
const observabilityActive = envActive || bodyActive;

const traceId = body.trace_id || body.task_id || body.execution_id || `n8n_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;
const status = body.status || (body.error_type ? 'failure' : 'success');
const defaultUrl = 'http://langfuse-web:3000';
const langfuseUrl = (body.langfuse_url || $env.LANGFUSE_URL || defaultUrl).replace(/\/$/, '');

const allowedPrefixes = [
  'http://langfuse-web:3000',
  'http://localhost:3010',
  'http://127.0.0.1:3010'
];
const hostedBlocked = /cloud\.langfuse\.com|api\.langfuse\.com|https?:\/\/[^/]*langfuse\.com/i.test(langfuseUrl);
const localAllowed = allowedPrefixes.some(prefix => langfuseUrl.startsWith(prefix));

const allowedMetadataKeys = [
  'workflow_id',
  'workflow_name',
  'execution_id',
  'route_id',
  'agent_target',
  'selected_model_alias',
  'status',
  'error_type',
  'duration_ms',
  'user_goal_hash',
  'approval_required',
  'approval_gates',
  'source'
];
const forbiddenKey = /prompt|completion|input|output|raw|text|document|content|api[_-]?key|authorization|cookie|password|secret|token|private/i;
const metadata = {};
for (const key of allowedMetadataKeys) {
  if (Object.prototype.hasOwnProperty.call(body, key) && !forbiddenKey.test(key)) {
    metadata[key] = body[key];
  }
}
metadata.trace_id = traceId;
metadata.status = status;
metadata.source = metadata.source || 'n8n-local-trace-emitter';
metadata.raw_payload_exported = false;
metadata.external_telemetry = false;

if (!observabilityActive) {
  return {
    emit_trace: false,
    trace_id: traceId,
    status: 'skipped',
    reason: 'observability profile inactive',
    metadata
  };
}

if (hostedBlocked || !localAllowed) {
  return {
    emit_trace: false,
    trace_id: traceId,
    status: 'refused',
    reason: 'Langfuse URL must be local-only',
    langfuse_url: langfuseUrl,
    metadata
  };
}

const publicKey = $env.LANGFUSE_PUBLIC_KEY || '';
const writeKey = $env.LANGFUSE_WRITE_KEY || '';
if (!publicKey || !writeKey) {
  return {
    emit_trace: false,
    trace_id: traceId,
    status: 'skipped',
    reason: 'Langfuse write keys not configured',
    langfuse_url: langfuseUrl,
    metadata
  };
}

const auth = Buffer.from(`${publicKey}:${writeKey}`).toString('base64');
const timestamp = body.timestamp || new Date().toISOString();
const eventId = `${traceId}-trace-create`;

return {
  emit_trace: true,
  trace_id: traceId,
  status: 'planned',
  langfuse_url: langfuseUrl,
  auth_header: `Basic ${auth}`,
  ingestion_body: {
    batch: [
      {
        id: eventId,
        timestamp,
        type: 'trace-create',
        body: {
          id: traceId,
          timestamp,
          name: `n8n.${metadata.workflow_name || metadata.workflow_id || 'workflow'}.${status}`,
          metadata
        }
      }
    ]
  }
};
